'use client';

import { useState } from 'react';
import { ChevronRight, ChevronDown, Edit2, Trash2, Plus, Package } from 'lucide-react';

type UnitNode = {
    id: number;
    name: string;
    code: string;
    conversionFactor: number;
    baseUnitId: number | null;
    children?: UnitNode[];
};

export function UnitTree({ units }: { units: UnitNode[] }) {
    // Separate root units (no base) from children for initial render if needed,
    // but assuming 'units' passed here is a nested tree or we build it.
    // For simplicity, let's assume the parent passes a list of Roots with populated Children.

    return (
        <div className="space-y-4">
            {units.map((unit) => (
                <UnitTreeNode key={unit.id} unit={unit} level={0} />
            ))}
        </div>
    );
}

function UnitTreeNode({ unit, level }: { unit: UnitNode; level: number }) {
    const [isExpanded, setIsExpanded] = useState(true);

    const hasChildren = unit.children && unit.children.length > 0;

    return (
        <div className="select-none">
            <div
                className={`
                    group flex items-center justify-between p-4 rounded-xl border transition-all duration-200
                    ${level === 0 ? 'bg-white border-gray-100 shadow-sm mb-2' : 'bg-gray-50/50 border-gray-100/50 ml-8 mt-2'}
                    hover:border-emerald-200 hover:shadow-md
                `}
            >
                <div className="flex items-center gap-4">
                    {/* Expand Toggle */}
                    <button
                        onClick={() => setIsExpanded(!isExpanded)}
                        className={`p-1 rounded-lg hover:bg-gray-100 text-gray-400 transition-colors ${!hasChildren && 'invisible'}`}
                    >
                        {isExpanded ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                    </button>

                    {/* Icon */}
                    <div className={`
                        w-10 h-10 rounded-lg flex items-center justify-center
                        ${level === 0 ? 'bg-emerald-100 text-emerald-600' : 'bg-blue-50 text-blue-500'}
                    `}>
                        <Package size={20} strokeWidth={2} />
                    </div>

                    {/* Info */}
                    <div>
                        <div className="flex items-center gap-2">
                            <h4 className="font-bold text-gray-900">{unit.name}</h4>
                            <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-gray-100 text-gray-500 tracking-wide border border-gray-200">
                                {unit.code}
                            </span>
                        </div>
                        <p className="text-sm text-gray-500 mt-0.5">
                            {level === 0
                                ? 'Base Unit (Count/Weight)'
                                : `1 ${unit.name} = ${unit.conversionFactor} parent units`
                            }
                        </p>
                    </div>
                </div>

                {/* Actions */}
                <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button className="p-2 text-gray-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-lg transition-colors" title="Edit">
                        <Edit2 size={16} />
                    </button>
                    <button className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors" title="Add Child Unit">
                        <Plus size={16} />
                    </button>
                    {level > 0 && (
                        <button className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors" title="Delete">
                            <Trash2 size={16} />
                        </button>
                    )}
                </div>
            </div>

            {/* Children Recursive Render */}
            {isExpanded && hasChildren && (
                <div className="border-l-2 border-gray-100 ml-6 pl-2">
                    {unit.children!.map((child) => (
                        <UnitTreeNode key={child.id} unit={child} level={level + 1} />
                    ))}
                </div>
            )}
        </div>
    );
}
